)
SELECT e.id, sp.id, 5, 'primary', 'lunge_plank_global_access', pos.order_index,
  FALSE, 1, 1,
  2, 0, 'low'
FROM coaching.exercise e
JOIN coaching.session_phase sp ON sp.key = 'prepare_and_access'
JOIN coaching.phase_order_slot pos ON pos.key = 'lunge_plank_global_access' AND pos.phase_id = sp.id
