  coaching_execution = '{"movement_description":"Place the rear foot on a box or bench and squat through the front leg while maintaining pelvis and knee control.","setup":["Choose the regression or leverage that lets the athlete perform Bulgarian Split Squat without pain.","Set the surface, support, wall, bar, box, or mat so it cannot move unexpectedly.","Start in the base body position with ribs, pelvis, shoulders, and hands/feet organized before the first rep."],"execution_steps":["Create tension before moving.","Place the rear foot on a box or bench and squat through the front leg while maintaining pelvis and knee control.","Move through only the range the athlete can own.","Return or reset with the same posture and control used at the start.","Stop the set when the quality gate is no longer met."],"coach_cues":["Front leg works","Soft back foot","Hips square","Slow lower"],"athlete_cues":["Control the front leg."],"breathing_cues":["Exhale through the hard part without breath-holding.","Keep breathing quiet enough that posture does not change."],"common_faults":["Back foot cramps","Front knee caves","Hopping for balance","Depth before control"],"quality_gate":["No pain, numbness, dizziness, or pressure symptoms.","Joint positions remain aligned through the intended range.","The athlete can finish the rep or hold without rushing, collapsing, or compensating.","The next repetition would look the same as the first."],"stop_signs":["Pain appears or increases.","The athlete loses the required body shape or joint position.","Grip, wrist, shoulder, trunk, hip, knee, or ankle control fails.","The athlete cannot breathe or safely exit the position."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Resilience Control Drill","Low-Impact Conditioning Finisher"],"pairs_well_after":["General Warmup","Movement Intelligence Shape Drill","Pattern-Specific Access Work"],"good_for_sessions":["squat_prep"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Pain appears in the required position or transition.","The athlete cannot control the required body shape safely.","The session priority requires fresh speed/power and this would create fatigue first.","The available surface, wall, bar, box, rings, or mat setup is unsafe."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex calisthenics movement demo recommended","Vortex Exercise Card Authoring Guide: Card v2 phase, taxonomy, dosage, scaling, and safety rules"],"internal_notes":["Film Bulgarian Split Squat from front and side angles where useful.","Show at least one regression and one progression.","Coach quality, alignment, and controlled bodyweight leverage before speed or volume."]}'::jsonb,
  updated_at = now()
WHERE slug = 'bulgarian-split-squat';

