-- Skater Step (skater-step) [insert]
UPDATE coaching.exercise SET
  name = 'Skater Step',
  description = 'Step side-to-side in a skater pattern, reaching the opposite leg behind without turning it into a maximal bound.',
  card_summary = 'Low-impact lateral step pattern that develops lateral rhythm, balance, and sustained side-to-side movement without high plyometric demand.',
  coach_language = 'Primary subrole: Low-Amplitude Elastic Conditioning. Place in Sustained Capacity when the intent is low-amplitude lateral conditioning and the athlete can maintain clean bodyweight leverage, breathing, and joint position.',
  athlete_language = 'Step, don''t leap.',
  movement_family = 'Low-amplitude lateral conditioning',
  primary_phase_key = 'sustained_capacity',
  phase_subrole = 'low_amplitude_elastic_conditioning',
  primary_order_slot = 'lateral_rhythm_repeatability',
  default_sets = 3,
  default_reps = NULL,
  default_work_seconds = 30,
  default_rest_seconds = 30,
  est_seconds_per_set = 60,
  movement_requirements = '{"primary_joint_actions":["lateral_weight_shift","single_leg_balance","hip_abduction_adduction","controlled_landing"],"primary_tissues":["gluteus_medius","adductors","calves","quadriceps"],"primary_motor_control_demands":["bodyweight_leverage_control","alignment_under_bodyweight_load","controlled_transition_or_hold"],"postural_shape":"Low-amplitude lateral conditioning","breathing_demand":"elevated_but_controlled","balance_demand":"moderate","coordination_demand":"high","impact_level":1}'::jsonb,
  coaching_execution = '{"movement_description":"Step side-to-side in a skater pattern, reaching the opposite leg behind without turning it into a maximal bound.","setup":["Choose the regression or leverage that lets the athlete perform Skater Step without pain.","Set the surface, support, wall, bar, box, or mat so it cannot move unexpectedly.","Start in the base body position with ribs, pelvis, shoulders, and hands/feet organized before the first rep."],"execution_steps":["Create tension before moving.","Step side-to-side in a skater pattern, reaching the opposite leg behind without turning it into a maximal bound.","Move through only the range the athlete can own.","Return or reset with the same posture and control used at the start.","Stop the set when the quality gate is no longer met."],"coach_cues":["Step, don''t leap","Knee tracks","Soft touch","Rhythm first"],"athlete_cues":["Step, don''t leap."],"breathing_cues":["Exhale through the hard part without breath-holding.","Keep breathing quiet enough that posture does not change."],"common_faults":["Max bounding","Knee caves","Loud contacts","Speed before control"],"quality_gate":["No pain, numbness, dizziness, or pressure symptoms.","Joint positions remain aligned through the intended range.","The athlete can finish the rep or hold without rushing, collapsing, or compensating.","The next repetition would look the same as the first."],"stop_signs":["Pain appears or increases.","The athlete loses the required body shape or joint position.","Grip, wrist, shoulder, trunk, hip, knee, or ankle control fails.","The athlete cannot breathe or safely exit the position."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Restore Breathing","Cooldown Mobility"],"pairs_well_after":["Prepare & Access","Movement Intelligence","Main Capacity Block"],"good_for_sessions":["squat_prep","general_warmup","landing_prep"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Pain appears in the required position or transition.","The athlete cannot control the required body shape safely.","The session priority requires fresh speed/power and this would create fatigue first.","The available surface, wall, bar, box, rings, or mat setup is unsafe."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex calisthenics movement demo recommended","Vortex Exercise Card Authoring Guide: Card v2 phase, taxonomy, dosage, scaling, and safety rules"],"internal_notes":["Film Skater Step from front and side angles where useful.","Show at least one regression and one progression.","Coach quality, alignment, and controlled bodyweight leverage before speed or volume."]}'::jsonb,
  updated_at = now()
WHERE slug = 'skater-step';

INSERT INTO coaching.exercise_phase_profile (
  exercise_id, phase_id, fit_weight, role, order_slot, order_index,
  freshness_required, fatigue_sensitivity, fatigue_cost, technical_complexity, impact_level, intensity_ceiling
)
SELECT e.id, sp.id, 5, 'primary', 'lateral_rhythm_repeatability', pos.order_index,
  FALSE, 2, 4,
  2, 1, 'high'
FROM coaching.exercise e
JOIN coaching.session_phase sp ON sp.key = 'sustained_capacity'
JOIN coaching.phase_order_slot pos ON pos.key = 'lateral_rhythm_repeatability' AND pos.phase_id = sp.id
WHERE e.slug = 'skater-step'
ON CONFLICT (exercise_id, phase_id) DO UPDATE SET
  role = EXCLUDED.role,
  order_slot = EXCLUDED.order_slot,
  order_index = EXCLUDED.order_index,
  fit_weight = EXCLUDED.fit_weight,
  freshness_required = EXCLUDED.freshness_required,
  fatigue_sensitivity = EXCLUDED.fatigue_sensitivity,
  fatigue_cost = EXCLUDED.fatigue_cost,
  technical_complexity = EXCLUDED.technical_complexity,
  impact_level = EXCLUDED.impact_level,
  intensity_ceiling = EXCLUDED.intensity_ceiling;

